import { Component, OnInit } from '@angular/core';
import { Router } from '@angular/router';
import { forkJoin, of } from 'rxjs';
import { catchError } from 'rxjs/operators';
import { ResumeTemplate, UsageLimit } from '../../../core/models/resume.model';
import { AuthService } from '../../../core/services/auth.service';
import { ResumeService } from '../../../core/services/resume.service';
import { TemplateFilterState } from '../template-filter-sidebar/template-filter-sidebar.component';

@Component({
  selector: 'app-template-dashboard',
  templateUrl: './template-dashboard.component.html'
})
export class TemplateDashboardComponent implements OnInit {
  readonly favoriteStorageKey = 'resume_ai_template_favorites';
  readonly categoryChips = ['All Templates', 'Simple', 'Modern', 'Creative', 'Developer', 'Fresher', 'Professional', 'Compact'];

  templates: ResumeTemplate[] = [];
  loading = true;
  search = '';
  sort = 'recommended';
  favoriteIds = new Set<number>();
  usageLimit: UsageLimit | null = null;
  selectedTemplate: ResumeTemplate | null = null;
  showUpgradeModal = false;
  importing = false;
  filters: TemplateFilterState = {
    roleType: '',
    experience: '',
    layout: '',
    style: '',
    category: '',
    isAtsFriendly: null,
    access: 'all'
  };

  constructor(
    private readonly resumeService: ResumeService,
    private readonly authService: AuthService,
    private readonly router: Router
  ) {
  }

  ngOnInit(): void {
    this.favoriteIds = this.readFavorites();
    const usageLimit$ = this.authService.isAuthenticated()
      ? this.resumeService.getUsageLimit().pipe(catchError(() => of(null)))
      : of(null);

    forkJoin({
      templates: this.resumeService.getTemplates(),
      usageLimit: usageLimit$
    }).subscribe({
      next: ({ templates, usageLimit }) => {
        this.templates = templates;
        this.usageLimit = usageLimit;
        this.loading = false;
      },
      error: () => {
        this.loading = false;
      }
    });
  }

  get filteredTemplates(): ResumeTemplate[] {
    const normalizedSearch = this.search.trim().toLowerCase();
    const filtered = this.templates.filter((template) => {
      const tags = this.parseJsonArray(template.tagsJson).join(' ').toLowerCase();
      const supports = this.parseJsonArray(template.supportedSectionsJson).join(' ').toLowerCase();
      const matchesSearch = !normalizedSearch || [
        template.name,
        template.category,
        template.roleType,
        template.experienceLevel,
        template.layoutType,
        template.styleType,
        tags,
        supports
      ].join(' ').toLowerCase().includes(normalizedSearch);

      const matchesCategory = !this.filters.category || template.category === this.filters.category;
      const matchesRole = !this.filters.roleType || template.roleType === this.filters.roleType;
      const matchesExperience = !this.filters.experience || template.experienceLevel === this.filters.experience;
      const matchesLayout = !this.filters.layout || template.layoutType === this.filters.layout;
      const matchesStyle = !this.filters.style || template.styleType === this.filters.style;
      const matchesAts = this.filters.isAtsFriendly === null || template.atsFriendly === this.filters.isAtsFriendly;
      const matchesAccess = this.filters.access === 'all'
        || (this.filters.access === 'free' && !template.premium)
        || (this.filters.access === 'premium' && template.premium);

      return matchesSearch
        && matchesCategory
        && matchesRole
        && matchesExperience
        && matchesLayout
        && matchesStyle
        && matchesAts
        && matchesAccess;
    });

    return this.sortTemplates(filtered);
  }

  onFiltersChange(filters: TemplateFilterState): void {
    this.filters = filters;
  }

  onSearchChange(search: string): void {
    this.search = search;
  }

  applyCategory(category: string): void {
    this.filters = {
      ...this.filters,
      category: category === 'All Templates' ? '' : category
    };
  }

  onPreview(template: ResumeTemplate): void {
    this.selectedTemplate = template;
  }

  onUseTemplate(template: ResumeTemplate): void {
    if (template.premium && !this.usageLimit?.premium) {
      this.showUpgradeModal = true;
      return;
    }

    this.resumeService.createEditorResume({ templateId: template.id, title: 'Untitled Resume' }).subscribe({
      next: (resume) => void this.router.navigate(['/resume-editor', resume.id, 'content'])
    });
  }

  onImportResume(event: Event): void {
    const input = event.target as HTMLInputElement;
    const file = input.files?.[0];
    if (!file) {
      return;
    }
    this.importing = true;
    this.resumeService.importResume(file).subscribe({
      next: ({ resumeId }) => {
        this.importing = false;
        void this.router.navigate(['/resume-editor', resumeId, 'content']);
      },
      error: () => {
        this.importing = false;
      }
    });
    input.value = '';
  }

  toggleFavorite(template: ResumeTemplate): void {
    const next = new Set(this.favoriteIds);
    if (next.has(template.id)) {
      next.delete(template.id);
    } else {
      next.add(template.id);
    }
    this.favoriteIds = next;
    localStorage.setItem(this.favoriteStorageKey, JSON.stringify(Array.from(next)));
  }

  private sortTemplates(templates: ResumeTemplate[]): ResumeTemplate[] {
    const sorted = [...templates];
    switch (this.sort) {
      case 'name':
        return sorted.sort((left, right) => left.name.localeCompare(right.name));
      case 'free-first':
        return sorted.sort((left, right) => Number(left.premium) - Number(right.premium));
      case 'premium-first':
        return sorted.sort((left, right) => Number(right.premium) - Number(left.premium));
      case 'ats-first':
        return sorted.sort((left, right) => Number(right.atsFriendly) - Number(left.atsFriendly));
      default:
        return sorted;
    }
  }

  private readFavorites(): Set<number> {
    try {
      const raw = localStorage.getItem(this.favoriteStorageKey);
      const parsed = raw ? JSON.parse(raw) as number[] : [];
      return new Set(Array.isArray(parsed) ? parsed : []);
    } catch {
      return new Set<number>();
    }
  }

  private parseJsonArray(value: string): string[] {
    try {
      const parsed = JSON.parse(value);
      return Array.isArray(parsed) ? parsed.map((item) => String(item)) : [];
    } catch {
      return [];
    }
  }
}
<app-loader *ngIf="loading" message="Loading templates"></app-loader>

<div *ngIf="!loading" class="space-y-6">
  <div class="shell-card p-8">
    <div class="flex flex-wrap items-start justify-between gap-4">
      <div class="max-w-3xl">
        <h2 class="section-title mt-2 text-4xl text-[#17172b] md:text-5xl">Choose a resume template</h2>
        <p class="mt-4 text-base leading-7 text-[#667085]">Start with an ATS-friendly design. You can customize or switch it later.</p>
      </div>
      <label class="btn-secondary cursor-pointer">
        <input type="file" class="hidden" accept=".pdf,.doc,.docx" (change)="onImportResume($event)">
        {{ importing ? 'Importing...' : 'Import existing resume' }}
      </label>
    </div>

    <div class="mt-8">
      <app-template-search [search]="search" (searchChange)="onSearchChange($event)"></app-template-search>
    </div>

    <div class="mt-6 flex flex-wrap gap-3">
      <button *ngFor="let category of categoryChips" type="button" class="rounded-full px-4 py-2 text-sm font-semibold transition"
        [ngClass]="(filters.category || 'All Templates') === category ? 'bg-[#17172b] text-white' : 'bg-[#f8f9ff] text-[#475467]'"
        (click)="applyCategory(category)">{{ category }}</button>
    </div>
  </div>

  <div class="grid gap-6 xl:grid-cols-[320px_1fr]">
    <app-template-filter-sidebar [filters]="filters" (filtersChange)="onFiltersChange($event)"></app-template-filter-sidebar>

    <section class="space-y-5">
      <app-template-grid [templates]="filteredTemplates" [favoriteIds]="favoriteIds" (preview)="onPreview($event)"
        (useTemplate)="onUseTemplate($event)" (toggleFavorite)="toggleFavorite($event)">
      </app-template-grid>
    </section>
  </div>
</div>

<div *ngIf="selectedTemplate" class="fixed inset-0 z-50 bg-[#0f172a]/60 p-4 overflow-auto">
  <div class="mx-auto max-w-6xl">
    <app-template-preview-modal [template]="selectedTemplate" [favorite]="favoriteIds.has(selectedTemplate.id)"
      (toggleFavorite)="toggleFavorite(selectedTemplate)" (close)="selectedTemplate = null">
    </app-template-preview-modal>
    <div class="mt-4 flex justify-end gap-3">
      <button class="btn-secondary" type="button" (click)="selectedTemplate = null">Back</button>
      <button class="btn-primary" type="button" (click)="onUseTemplate(selectedTemplate)">Use this template</button>
    </div>
  </div>
</div>

<div *ngIf="showUpgradeModal" class="fixed inset-0 z-50 flex items-center justify-center bg-[#0f172a]/60 p-4">
  <div class="w-full max-w-xl rounded-3xl bg-white p-8">
    <h3 class="mt-2 text-center text-3xl font-extrabold text-[#17172b]">Need more than one resume?</h3>
    <p class="mx-auto mt-3 max-w-md text-center text-[#667085]">Your free plan includes only one resume. Upgrade to create another.</p>
    <div class="mt-8 grid gap-3">
      <a routerLink="/pricing" class="btn-primary text-center">View Plans</a>
      <button class="btn-secondary" type="button" (click)="showUpgradeModal = false">Cancel</button>
    </div>
  </div>
</div>
